import { useState, useEffect, useCallback, useRef } from 'react';
import type React from 'react';
import { audioManager } from '../../services/AudioManager';

// ============================================
// 🎛️ ТИПЫ
// ============================================

interface ChannelState {
  volume: number;   // dB
  mute: boolean;
  solo: boolean;
}

interface EQState {
  low: number;    // -12 to +12 dB
  mid: number;
  high: number;
}

// ============================================
// 🎛️ КОМПОНЕНТ МИКШЕРА (560px ширина)
// ============================================

const CHANNEL_CONFIG: { key: string; label: string; color: string; defaultDb: number }[] = [
  { key: 'chords',  label: 'CHORDS',  color: '#00bcd4', defaultDb: -6 },
  { key: 'guitar',  label: 'GUITAR',  color: '#00FF9D', defaultDb: 6 },
  { key: 'bass',    label: 'BASS',    color: '#ff9800', defaultDb: 0 },
  { key: 'drums',   label: 'DRUMS',   color: '#e94560', defaultDb: 0 },
  { key: 'master',  label: 'MASTER',  color: '#ffffff', defaultDb: 0 },
];

const EQ_BANDS: { key: 'low' | 'mid' | 'high'; label: string; freq: string; color: string }[] = [
  { key: 'low',  label: 'LOW',  freq: '60Hz',  color: '#ff6b6b' },
  { key: 'mid',  label: 'MID',  freq: '1kHz',  color: '#ffd93d' },
  { key: 'high', label: 'HIGH', freq: '8kHz',  color: '#6bcb77' },
];

const DEFAULT_CHANNELS: Record<string, ChannelState> = {
  chords: { volume: -6, mute: false, solo: false },
  guitar: { volume: 6, mute: false, solo: false },
  bass: { volume: 0, mute: false, solo: false },
  drums: { volume: 0, mute: false, solo: false },
  master: { volume: 0, mute: false, solo: false },
};

const DEFAULT_EQ: EQState = { low: 0, mid: 0, high: 0 };

// ============================================
// 🎛️ ВЕРТИКАЛЬНЫЙ ФЕЙДЕР (drag up/down)
// ============================================
interface VerticalFaderProps {
  channel: string;
  volume: number;
  color: string;
  mute: boolean;
  onVolumeChange: (channel: string, db: number) => void;
}

const VerticalFader: React.FC<VerticalFaderProps> = ({ channel, volume, color, mute, onVolumeChange }) => {
  const faderRef = useRef<HTMLDivElement>(null);
  const isDragging = useRef(false);

  const dbToPercent = (db: number): number => {
    // -60 dB = 0%, 12 dB = 100%
    return Math.max(0, Math.min(100, ((db + 60) / 72) * 100));
  };

  const percentToDb = (percent: number): number => {
    return Math.round(((percent / 100) * 72 - 60) * 2) / 2; // round to 0.5
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    e.preventDefault();
    isDragging.current = true;
    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);
    // immediate update from click position
    updateFromEvent(e.clientY);
  };

  const handleMouseMove = (e: MouseEvent) => {
    if (!isDragging.current) return;
    updateFromEvent(e.clientY);
  };

  const handleMouseUp = () => {
    isDragging.current = false;
    document.removeEventListener('mousemove', handleMouseMove);
    document.removeEventListener('mouseup', handleMouseUp);
  };

  const updateFromEvent = (clientY: number) => {
    if (!faderRef.current) return;
    const rect = faderRef.current.getBoundingClientRect();
    const relativeY = clientY - rect.top;
    const percent = Math.max(0, Math.min(100, ((rect.height - relativeY) / rect.height) * 100));
    const db = percentToDb(percent);
    onVolumeChange(channel, db);
  };

  const vuPercent = mute ? 0 : dbToPercent(volume);

  return (
    <div
      ref={faderRef}
      onMouseDown={handleMouseDown}
      style={{
        width: '100%',
        height: '130px',
        background: 'rgba(0,0,0,0.5)',
        borderRadius: '4px',
        position: 'relative',
        overflow: 'hidden',
        border: '1px solid rgba(255,255,255,0.06)',
        cursor: 'pointer',
        userSelect: 'none',
        touchAction: 'none',
      }}
    >
      {/* Track background ticks */}
      {[0, 25, 50, 75].map(pct => (
        <div
          key={pct}
          style={{
            position: 'absolute',
            bottom: `${pct}%`,
            left: 0,
            right: 0,
            height: '1px',
            background: 'rgba(255,255,255,0.04)',
          }}
        />
      ))}

      {/* Fill bar */}
      <div
        style={{
          position: 'absolute',
          bottom: 0,
          left: '20%',
          width: '60%',
          height: `${vuPercent}%`,
          background: mute
            ? 'rgba(255,255,255,0.1)'
            : `linear-gradient(0deg, ${color}66, ${color})`,
          transition: isDragging.current ? 'none' : 'height 0.08s ease',
          borderRadius: '3px',
          minHeight: '3px',
        }}
      />

      {/* Clip indicator */}
      {volume > 6 && !mute && (
        <div
          style={{
            position: 'absolute',
            top: 0,
            left: 0,
            right: 0,
            height: '6px',
            background: '#ff4444',
            animation: 'pulse 0.5s infinite',
          }}
        />
      )}

      {/* Drag handle */}
      <div
        style={{
          position: 'absolute',
          left: '8%',
          right: '8%',
          bottom: `${vuPercent}%`,
          height: '4px',
          background: mute ? 'rgba(255,255,255,0.15)' : '#fff',
          borderRadius: '2px',
          opacity: 0.7,
          transform: 'translateY(50%)',
          transition: isDragging.current ? 'none' : 'bottom 0.08s ease',
          pointerEvents: 'none',
        }}
      />
    </div>
  );
};

const StudioMixer: React.FC = () => {
  const [channels, setChannels] = useState<Record<string, ChannelState>>(DEFAULT_CHANNELS);
  const [eq, setEq] = useState<EQState>(DEFAULT_EQ);

  useEffect(() => {
    // Инициализируем AudioManager при монтировании
    audioManager.init().catch(console.warn);
  }, []);

  // Синхронизация каналов с AudioManager
  useEffect(() => {
    Object.entries(channels).forEach(([key, state]) => {
      try {
        audioManager.setVolume(key as any, state.volume);
        audioManager.setMute(key as any, state.mute);
      } catch (err) {
        console.warn(`🎚️ Channel ${key} error:`, err);
      }
    });
  }, [channels]);

  // Синхронизация EQ с AudioManager
  useEffect(() => {
    try {
      audioManager.setEQ('low', eq.low);
      audioManager.setEQ('mid', eq.mid);
      audioManager.setEQ('high', eq.high);
    } catch (err) {
      console.warn('🎚️ EQ sync error:', err);
    }
  }, [eq]);

  const handleVolumeChange = useCallback((channel: string, db: number) => {
    setChannels(prev => ({
      ...prev,
      [channel]: { ...prev[channel], volume: db }
    }));
  }, []);

  const handleMuteToggle = useCallback((channel: string) => {
    setChannels(prev => ({
      ...prev,
      [channel]: { ...prev[channel], mute: !prev[channel].mute }
    }));
  }, []);

  const handleSoloToggle = useCallback((channel: string) => {
    setChannels(prev => {
      const newChannels = { ...prev };
      const newSoloState = !prev[channel].solo;
      Object.keys(newChannels).forEach(key => {
        newChannels[key] = { ...newChannels[key], solo: key === channel ? newSoloState : false };
      });
      return newChannels;
    });
  }, []);

  const handleEQChange = useCallback((band: 'low' | 'mid' | 'high', value: number) => {
    setEq(prev => ({ ...prev, [band]: value }));
  }, []);

  return (
    <div style={{
      width: '100%',
      background: '#0d0e14',
      borderRadius: '8px',
      border: '1px solid rgba(255,255,255,0.08)',
      overflow: 'hidden',
      fontFamily: "'Inter', system-ui, sans-serif",
    }}>
      
      {/* ===== HEADER ===== */}
      <div style={{
        padding: '10px 16px',
        background: 'linear-gradient(180deg, #151620 0%, #0d0e14 100%)',
        borderBottom: '1px solid rgba(255,255,255,0.06)',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
      }}>
        <span style={{ fontSize: '13px', fontWeight: 800, color: 'rgba(255,255,255,0.4)', letterSpacing: '1px', textTransform: 'uppercase' }}>
          🎛️ Studio Mixer
        </span>
        <span style={{ fontSize: '10px', color: 'rgba(255,255,255,0.2)', letterSpacing: '0.5px' }}>
          VOLUME
        </span>
      </div>

      {/* ===== CHANNEL STRIPS ===== */}
      <div style={{
        display: 'flex',
        gap: '6px',
        padding: '12px 12px 8px',
        overflowX: 'auto',
      }}>
        {CHANNEL_CONFIG.map(ch => {
          const state = channels[ch.key] || { volume: ch.defaultDb, mute: false, solo: false };
          
          return (
            <div key={ch.key} style={{
              flex: '1 0 0',
              minWidth: '64px',
              maxWidth: '84px',
              background: 'rgba(255,255,255,0.02)',
              borderRadius: '8px',
              border: '1px solid rgba(255,255,255,0.05)',
              padding: '6px 4px 8px',
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              gap: '5px',
              transition: 'all 0.2s',
              opacity: state.mute ? 0.35 : 1,
            }}>
              
              {/* Vertical Fader (replaces VU meter + range input) */}
              <VerticalFader
                channel={ch.key}
                volume={state.volume}
                color={ch.color}
                mute={state.mute}
                onVolumeChange={handleVolumeChange}
              />

              {/* Label */}
              <span style={{
                fontSize: '9px',
                fontWeight: 800,
                color: state.mute ? 'rgba(255,255,255,0.2)' : ch.color,
                letterSpacing: '0.5px',
                textTransform: 'uppercase',
                textAlign: 'center',
                lineHeight: 1.2,
                whiteSpace: 'nowrap',
              }}>
                {ch.key === 'master' ? 'MSTR' : ch.key.toUpperCase()}
              </span>

              {/* dB value — крупнее! */}
              <span style={{
                fontSize: '13px',
                fontWeight: 800,
                color: state.mute ? 'rgba(255,255,255,0.15)' : 'rgba(255,255,255,0.6)',
                fontFamily: 'monospace',
                lineHeight: 1,
                letterSpacing: '-0.5px',
              }}>
                {state.volume > 0 ? `+${state.volume}` : state.volume}
                <span style={{ fontSize: '10px', fontWeight: 600, opacity: 0.5 }}>dB</span>
              </span>

              {/* M / S buttons */}
              <div style={{ display: 'flex', gap: '3px', width: '100%' }}>
                <button
                  onClick={() => handleMuteToggle(ch.key)}
                  style={{
                    flex: 1,
                    padding: '3px 0',
                    fontSize: '9px',
                    fontWeight: 900,
                    border: 'none',
                    borderRadius: '4px',
                    cursor: 'pointer',
                    background: state.mute ? ch.color : 'rgba(255,255,255,0.06)',
                    color: state.mute ? '#000' : 'rgba(255,255,255,0.3)',
                    transition: '0.15s',
                    letterSpacing: '0.5px',
                  }}
                >
                  M
                </button>
                <button
                  onClick={() => handleSoloToggle(ch.key)}
                  style={{
                    flex: 1,
                    padding: '3px 0',
                    fontSize: '9px',
                    fontWeight: 900,
                    border: 'none',
                    borderRadius: '4px',
                    cursor: 'pointer',
                    background: state.solo ? '#ffd93d' : 'rgba(255,255,255,0.06)',
                    color: state.solo ? '#000' : 'rgba(255,255,255,0.3)',
                    transition: '0.15s',
                    letterSpacing: '0.5px',
                  }}
                >
                  S
                </button>
              </div>
            </div>
          );
        })}
      </div>

      {/* ===== EQ SECTION ===== */}
      <div style={{
        margin: '4px 12px 12px',
        background: 'rgba(255,255,255,0.015)',
        borderRadius: '8px',
        border: '1px solid rgba(255,255,255,0.04)',
        padding: '10px 12px',
      }}>
        <div style={{
          fontSize: '10px',
          fontWeight: 800,
          color: 'rgba(255,255,255,0.25)',
          letterSpacing: '1px',
          textTransform: 'uppercase',
          marginBottom: '10px',
          textAlign: 'center',
        }}>
          ⚡ Equalizer
        </div>

        <div style={{ display: 'flex', gap: '10px', justifyContent: 'center' }}>
          {EQ_BANDS.map(band => (
            <div key={band.key} style={{
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              gap: '4px',
              flex: 1,
            }}>
              {/* Knob circle */}
              <div style={{
                width: '48px',
                height: '48px',
                borderRadius: '50%',
                background: `rgba(255,255,255,0.05)`,
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                position: 'relative',
                cursor: 'pointer',
                border: `2px solid ${band.color}${(eq[band.key] !== 0) ? '88' : '22'}`,
              }}>
                <div style={{
                  width: '30px',
                  height: '30px',
                  borderRadius: '50%',
                  background: '#1a1b24',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  border: '1px solid rgba(255,255,255,0.06)',
                }}>
                  <div style={{
                    width: '3px',
                    height: '12px',
                    background: band.color,
                    borderRadius: '2px',
                    transform: `rotate(${(eq[band.key] / 12) * 45}deg)`,
                    transition: 'transform 0.1s',
                  }} />
                </div>
              </div>

              <input
                type="range"
                min="-12"
                max="12"
                step="0.5"
                value={eq[band.key]}
                onChange={(e) => handleEQChange(band.key, Number(e.target.value))}
                style={{
                  width: '100%',
                  height: '3px',
                  accentColor: band.color,
                  cursor: 'pointer',
                }}
                title={`${band.label}: ${eq[band.key]} dB`}
              />

              <span style={{
                fontSize: '9px',
                fontWeight: 700,
                color: 'rgba(255,255,255,0.3)',
                letterSpacing: '0.5px',
              }}>
                {band.label}
              </span>

              <span style={{
                fontSize: '8px',
                fontWeight: 600,
                color: 'rgba(255,255,255,0.15)',
                fontFamily: 'monospace',
              }}>
                {band.freq}
              </span>

              <span style={{
                fontSize: '10px',
                fontWeight: 800,
                color: eq[band.key] !== 0 ? band.color : 'rgba(255,255,255,0.2)',
                fontFamily: 'monospace',
              }}>
                {eq[band.key] > 0 ? `+${eq[band.key]}` : eq[band.key]}
              </span>
            </div>
          ))}
        </div>
      </div>

      <style>{`
        @keyframes pulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.4; }
        }
        input[type="range"]::-webkit-slider-thumb {
          -webkit-appearance: none;
          width: 12px;
          height: 12px;
          border-radius: 50%;
          cursor: pointer;
        }
        input[type="range"]::-moz-range-thumb {
          width: 12px;
          height: 12px;
          border-radius: 50%;
          cursor: pointer;
          border: none;
        }
      `}</style>
    </div>
  );
};

export default StudioMixer;
export type { ChannelState, EQState };

